        return 1

    ball_x = obs[99]
    ball_y = obs[101]
    paddle_x = obs[72]

    # Persistent state for velocity
    if not hasattr(select_action, "prev_ball_y"):
        select_action.prev_ball_y = ball_y
        select_action.prev_ball_x = ball_x
        if ball_x < paddle_x:
            return 3
        elif ball_x > paddle_x:
            return 2
        return 0

    dy = ball_y - select_action.prev_ball_y
    dx = ball_x - select_action.prev_ball_x
    select_action.prev_ball_y = ball_y
    select_action.prev_ball_x = ball_x

    # Predict ball x when it reaches paddle y level (approximately y=195)
    target_y = 195
    if dy < 0:  # ball moving up
        # Direct chase with moderate deadzone
        if ball_x < paddle_x - 10:
            return 3
        elif ball_x > paddle_x + 10:
            return 2
        return 0
    else:  # ball moving down
        if dy == 0:
            dy = 1
        steps_to_paddle = (target_y - ball_y) / dy
        predicted_x = ball_x + dx * steps_to_paddle
        predicted_x = max(55, min(191, predicted_x))

        # Move toward predicted position with proportional speed
        diff = predicted_x - paddle_x
        if abs(diff) > 25:
            if diff > 0:
                return 2
            else:
                return 3
